{"code":"import json

with open(locals()['var_function-call-2661118915962742960'], 'r') as f:
    civic_docs = json.load(f)

check_projects = [
    "Trancas Canyon Park Playground",
    "Permanent Skate Park",
    "Bluffs Park Workout Station"
]

